import { keyframes } from '@emotion/react';

import { ChevronLeftIcon, ChevronRightIcon } from '../Icon';

export function getContentAnimation(width: number) {
  const showAnimation = keyframes`
  from { opacity: 0 }
  80%  { opacity: 0 }
  to   { opacity: 1 }`;
  const openAnimation = keyframes`
  from { width: 50px }
  to   { width: ${width}px }`;

  return {
    open: `${openAnimation} .2s cubic-bezier(0, 0, 0.2, 1)`,
    show: `${showAnimation} .25s linear`,
  };
}

export function getCollapseIcon(position: 'left' | 'right', isExpanded: boolean) {
  if (position === 'right') {
    return isExpanded ? ChevronRightIcon : ChevronLeftIcon;
  }
  return isExpanded ? ChevronLeftIcon : ChevronRightIcon;
}
